let now = new Date();

const reportHour = 19;

let lastRun = new Date(now);
lastRun.setHours(reportHour, 0, 0, 0);

if (now.getHours() < reportHour) {
  lastRun.setDate(lastRun.getDate() - 1);
}

let prevRun = new Date(lastRun);
prevRun.setDate(prevRun.getDate() - 1);

// =========================
// 🧠 فلترة بالتاريخ
let all = items.filter(item => {
  const rawDate = item.json.pubDate || item.json.isoDate;
  if (!rawDate) return false;

  const d = new Date(rawDate);
  return !isNaN(d) && d > prevRun && d <= lastRun;
});

// =========================
// 🔗 تنظيف اللينك
function cleanLink(link, content) {
  if (!link) return "";

  if (link.includes("news.google.com")) {
    try {
      const urlObj = new URL(link);
      let real = new URLSearchParams(urlObj.search).get("url");

      if (!real && content) {
        const match = content.match(/href="(https?:\/\/[^"]+)"/);
        if (match && !match[1].includes("news.google.com")) {
          real = match[1];
        }
      }

      if (real) return decodeURIComponent(real);
    } catch (e) {}
  }

  return link;
}

// =========================
// 📦 فلترة لوجيستكس (خفيفة)
let logisticsOnly = all.filter(item => {
  const text = (
    (item.json.title || "") + " " +
    (item.json.contentSnippet || "") + " " +
    (item.json.summary || "")
  ).toLowerCase();

  return (
    text.includes("logistics") ||
    text.includes("supply chain") ||
    text.includes("freight") ||
    text.includes("shipping") ||
    text.includes("transport") ||
    text.includes("cargo")
  );
});

// =========================
// 🔥 فلترة قوية (اختياري)
let strong = logisticsOnly.filter(item => {
  const text = (
    (item.json.title || "") + " " +
    (item.json.contentSnippet || "") + " " +
    (item.json.summary || "")
  ).toLowerCase();

  return (
    text.includes("disruption") ||
    text.includes("delay") ||
    text.includes("crisis") ||
    text.includes("risk") ||
    text.includes("capacity") ||
    text.includes("demand")
  );
});

// =========================
// 🧠 لو قليل → استخدم العادي
let final = strong.length >= 7 ? strong : logisticsOnly;

// =========================
// ترتيب
final.sort((a, b) => {
  const score = (txt) => {
    txt = (txt || "").toLowerCase();
    let s = 0;
    if (txt.includes("global")) s += 3;
    if (txt.includes("crisis") || txt.includes("risk")) s += 2;
    if (txt.includes("supply chain")) s += 2;
    if (txt.includes("freight")) s += 1;
    return s;
  };

  return score(b.json.title) - score(a.json.title);
});

// =========================
// 🎯 خد 10
final = final.slice(0, 10);

// =========================
// 📤 Output
return final.map(item => ({
  json: {
    title: item.json.title || "",
    content: item.json.contentSnippet || item.json.summary || "",
    link: cleanLink(
      item.json.link || item.json.guid || item.json.url,
      item.json.content
    ),
    date: item.json.pubDate || item.json.isoDate || ""
  }
}));

let results = [];

for (const i of items) {
  let raw = i.json.output || "";

  // نشيل أي markdown
  raw = raw.replace(/```json|```/g, "").trim();

  // نحاول نلقط كل JSON object جوه النص
  const matches = raw.match(/{[\s\S]*?}/g);

  if (!matches) continue;

  for (const m of matches) {
    try {
      const obj = JSON.parse(m);
      results.push(obj);
    } catch (e) {}
  }
}

// خد أول 7
results = results.slice(0, 7);

// رجعهم كـ messages
return results.map(item => ({
  json: {
    text: `📦 Logistics News

${item.title || "—"}

📌 ملخص:
${item.translation || "—"}

⚡ التأثير:
${item.impact || "—"}

🔗 ${item.link || "—"}`
  }
}));
